INSERT INTO project_evaluations (evaluation_id, project_id, created_at, created_by, action, status_after, score_total, score_impact, score_risk, score_complexity, monthly_savings, annual_savings, payback_period_months, roi_first_year, hours_saved_per_month, inputs_json, answers_json, weights_json, impact_score, effort_score, is_current) VALUES (4, 'MX-DDD-0003', '2026-03-09 16:25:05', 'Xiomara Monroy', 'approved', 'approved', 83.0, 25.0, 30.0, 28.0, 2400.0, 28800.0, 0.35, 3328.5714285714284, 96.0, '{"name": "Automatización Rotaciones MX", "description": "\nEl Proyecto Rotaciones MX tiene como objetivo estandarizar y automatizar la generación del template de Rotaciones para el cliente Bimbo de México, a partir de archivos provenientes de WPO (Worldpanel Online).\nActualmente, los archivos de entrada de WPO contienen información clave para KPIs y algunos demográficos, pero no incluyen todas las dimensiones requeridas por el template estándar de Rotaciones, lo que genera brechas que deben ser gestionadas mediante reglas claras de negocio y decisiones documentadas.\nEste proyecto aplica a múltiples categorías y países, y no se limita a una sola marca o familia de productos.", "country": "MX", "owner": "DDD", "current_time_per_task": 8.0, "tasks_per_month": 30, "staff_count": 1, "avg_salary_per_hour": 25.0, "time_reduction_percent": 40, "development_hours": 120, "development_cost_per_hour": 7, "maintenance_monthly": 0.0, "implementation_complexity": 2, "risk_level": 1}', NULL, NULL, NULL, NULL, 0) ON CONFLICT (evaluation_id) DO NOTHING;
INSERT INTO project_evaluations (evaluation_id, project_id, created_at, created_by, action, status_after, score_total, score_impact, score_risk, score_complexity, monthly_savings, annual_savings, payback_period_months, roi_first_year, hours_saved_per_month, inputs_json, answers_json, weights_json, impact_score, effort_score, is_current) VALUES (5, 'MX-DDD-0004', '2026-03-17 17:49:12', 'Xiomara Monroy', 'approved', 'approved', 78.0, 20.0, 30.0, 28.0, 500.0, 6000.0, 0.28, 4185.714285714285, 20.0, '{"name": "Actualización VBA Walmart Frescos", "description": "Se necesitan agregar nuevos slides a la macro de Walmart Frescos sin romper la estructura interna de lo que ya se genera. Además de actualizar el template", "country": "MX", "owner": "DDD", "current_time_per_task": 40.0, "tasks_per_month": 1, "staff_count": 2, "avg_salary_per_hour": 25.0, "time_reduction_percent": 25, "development_hours": 20, "development_cost_per_hour": 7, "maintenance_monthly": 0.0, "implementation_complexity": 2, "risk_level": 1}', NULL, NULL, NULL, NULL, 0) ON CONFLICT (evaluation_id) DO NOTHING;
INSERT INTO project_evaluations (evaluation_id, project_id, created_at, created_by, action, status_after, score_total, score_impact, score_risk, score_complexity, monthly_savings, annual_savings, payback_period_months, roi_first_year, hours_saved_per_month, inputs_json, answers_json, weights_json, impact_score, effort_score, is_current) VALUES (6, 'HI-DDD-0001', '2026-03-30 16:40:08', 'Xiomara Monroy', 'approved', 'approved', 62.0, 30.0, 18.0, 14.0, 562500.0, 6750000.0, 0.0021333333333333334, 562400.0, 22500.0, '{"name": "SMART INTAKE DM ", "description": "Implementar un agente inteligente que:\n\nIdentifique el tipo de solicitud que el comercial desea enviar.\nRealice las preguntas necesarias para recopilar la información completa según las reglas de Data Management.\nGenere automáticamente un correo estructurado ± con CC al solicitante hacia la casilla de Data Management.\nEn fase futura: Complemente o actualice un ticket en Jira para evitar intervención manual.\n\nEl agente no procesará información, no validará errores del negocio ni reemplazará actividades propias de Data Management.\nSu única función es capturar, validar presencia de datos requeridos y entregar un input completo y útil.", "country": "HISPANIC", "owner": "DDD", "current_time_per_task": 30.0, "tasks_per_month": 100, "staff_count": 15, "avg_salary_per_hour": 25.0, "time_reduction_percent": 50, "development_hours": 120, "development_cost_per_hour": 10, "maintenance_monthly": 0.0, "implementation_complexity": 4, "risk_level": 3}', NULL, NULL, NULL, NULL, 0) ON CONFLICT (evaluation_id) DO NOTHING;
INSERT INTO project_evaluations (evaluation_id, project_id, created_at, created_by, action, status_after, score_total, score_impact, score_risk, score_complexity, monthly_savings, annual_savings, payback_period_months, roi_first_year, hours_saved_per_month, inputs_json, answers_json, weights_json, impact_score, effort_score, is_current) VALUES (7, 'LA-OSCAROCHOA-0001', '2026-04-13 18:38:23', 'Xiomara Monroy', 'evaluation_saved', 'handed_off', 80.0, 35.0, 24.0, 21.0, 7680000.0, 92160000.0, 0.00025, 4799900.0, 307200.0, '{"name": "SOP Latam", "description": "El agente busca transformar el conocimiento operativo disperso en procesos estandarizados y gobernables, centralizados en un repositorio único de consulta para toda la compañía, reduciendo reprocesos, dependencia de personas clave y habilitando eficiencia y automatización a escala LATAM.", "country": "LATAM", "owner": "OSCAROCHOA", "current_time_per_task": 32.0, "tasks_per_month": 200, "staff_count": 60, "avg_salary_per_hour": 25.0, "time_reduction_percent": 80, "development_hours": 80, "development_cost_per_hour": 24, "maintenance_monthly": 0.0, "implementation_complexity": 3, "risk_level": 2}', NULL, NULL, NULL, NULL, 0) ON CONFLICT (evaluation_id) DO NOTHING;
INSERT INTO project_evaluations (evaluation_id, project_id, created_at, created_by, action, status_after, score_total, score_impact, score_risk, score_complexity, monthly_savings, annual_savings, payback_period_months, roi_first_year, hours_saved_per_month, inputs_json, answers_json, weights_json, impact_score, effort_score, is_current) VALUES (8, 'LA-COPILOT-0001', '2026-04-23 03:29:23', 'Xiomara Monroy', 'approved', 'approved', 64.0, 25.0, 18.0, 21.0, 5250000.0, 63000000.0, 0.00017142857142857143, 6999900.0, 210000.0, '{"name": "Implementaci\u00f3n de Copilot", "description": "Implementaci\u00f3n de Copilot Agents en LATAM para optimizar procesos de negocio mediante inteligencia artificial. El programa incluye formaci\u00f3n de Champions, identificaci\u00f3n de casos de uso priorizados por impacto y viabilidad, y gobernanza distribuida en equipos. Data Developers participa en construcci\u00f3n de agentes propios, soporte a implementaciones de otros equipos, y aseguramiento de gobernanza y mejores pr\u00e1cticas en el uso de IA.", "country": "LATAM", "owner": "COPILOT", "current_time_per_task": 30.0, "tasks_per_month": 100, "staff_count": 200, "avg_salary_per_hour": 25.0, "time_reduction_percent": 35, "development_hours": 90, "development_cost_per_hour": 10, "maintenance_monthly": 0.0, "implementation_complexity": 3, "risk_level": 3}', NULL, NULL, NULL, NULL, 0) ON CONFLICT (evaluation_id) DO NOTHING;
